// ── Extraire le body ────────────────────────────────────────────────────────
const body = $input.item.json.body || $input.item.json;

const prestataire_id = body.prestataire_id || null;
const prompt        = body.prompt || body.description || body.idee || '';
const prix_input    = parseFloat(body.prix || body.price || 0);
const image_url     = body.image_url || null;
const category_id   = parseInt(body.category_id) || null;

// ── Validation ───────────────────────────────────────────────────────────────
const errors = [];

if (!prestataire_id || isNaN(parseInt(prestataire_id))) {
  errors.push('prestataire_id est requis (entier)');
}
if (!prompt || prompt.trim().length < 5) {
  errors.push('prompt/description est requis (minimum 5 caractères)');
}
if (prix_input < 0) {
  errors.push('prix doit être >= 0');
}

if (errors.length > 0) {
  return { json: { valid: false, errors, message: 'Validation échouée' } };
}

// ── Image : extraire le filename si path complet ──────────────────────────────
let imageValue = image_url;
if (image_url && typeof image_url === 'string' && image_url.includes('/')) {
  const parts = image_url.split('/');
  imageValue = parts[parts.length - 1] || image_url;
}

// ── Prompt Claude pour service (tuteur) ───────────────────────────────────────
const promptText = `Tu es un assistant pour CampusLink, plateforme de services entre étudiants et tuteurs.

Un tuteur veut créer une offre de service sur la plateforme.
Prix indicatif : ${prix_input > 0 ? prix_input + '€' : 'non précisé'}.

Voici sa description en langage naturel :
"""${prompt}"""

Génère une offre de service structurée et professionnelle (titre + description).
Réponds UNIQUEMENT avec ce JSON brut (sans markdown, sans backticks) :
{
  "title": "[titre clair du service, ex: Cours de maths niveau lycée, 10 à 80 caractères]",
  "description": "[description complète, méthode, objectifs, 3 à 6 phrases]",
  "prix": ${prix_input > 0 ? prix_input : 'nombre décimal suggéré selon le contexte (ex: 25.00)'}
}

Règles strictes :
- title : court, accrocheur, max 100 caractères
- description : professionnelle, attirante pour des étudiants
- prix : nombre décimal uniquement, jamais de texte
- Réponds UNIQUEMENT avec le JSON, rien d'autre`;

return {
  json: {
    valid: true,
    prompt: promptText,
    meta: {
      prestataire_id:  parseInt(prestataire_id),
      image:           imageValue,
      category_id:     category_id || null,
      prix_input
    }
  }
};

// ── Extraire le texte brut d'OpenRouter ─────────────────────────────────────
const body = $input.item.json;
let rawText = '';

try {
  rawText = body.choices[0].message.content || '';
} catch (e) {
  throw new Error('Réponse OpenRouter invalide : ' + JSON.stringify(body).substring(0, 300));
}

const meta = $('Valider & Préparer Prompt').item.json.meta;

try {
  let cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  const start = cleaned.indexOf('{');
  const end   = cleaned.lastIndexOf('}');

  if (start === -1 || end === -1) {
    throw new Error('Aucun JSON dans la réponse');
  }

  const parsed = JSON.parse(cleaned.substring(start, end + 1));
  const title = String(parsed.title || parsed.titre || 'Service').substring(0, 200).trim();
  const desc  = String(parsed.description || parsed.message || '').trim();
  const prix  = parseFloat(parsed.prix || parsed.price) || meta.prix_input || 10;

  if (prix <= 0) throw new Error('Prix invalide');

  return {
    json: {
      ok: true,
      title,
      description: desc || title,
      price: prix,
      prestataire_id: meta.prestataire_id,
      image: meta.image || null,
      category_id: meta.category_id
    }
  };
} catch (e) {
  return {
    json: {
      ok: true,
      title: 'Service CampusLink',
      description: rawText.substring(0, 500),
      price: meta.prix_input > 0 ? meta.prix_input : 10,
      prestataire_id: meta.prestataire_id,
      image: meta.image || null,
      category_id: meta.category_id
    }
  };
}

const db  = $input.item.json;
const svc = $('Parser Réponse Claude').item.json;
const pubId = db['LAST_INSERT_ID()'] || db.service_id || db.insertId || null;

return {
  json: {
    success:    true,
    service_id: pubId,
    message:    'Service créé et enregistré avec succès',
    service: {
      id:            pubId,
      title:         svc.title,
      description:   svc.description,
      price:         svc.price,
      prestataire_id: svc.prestataire_id,
      status:        'EN_ATTENTE'
    }
  }
};

const data = $input.item.json;
return {
  json: {
    success: false,
    message: data.message || 'Validation échouée',
    errors:  data.errors  || []
  }
};

const err = $input.item.json;
const svc = $('Parser Réponse Claude').item.json;
return {
  json: {
    success: false,
    message: 'Erreur lors de l\'insertion en base de données',
    error:   JSON.stringify(err),
    service_genere: { title: svc.title, description: svc.description }
  }
};
